import{_ as e,o as l,c as n,ag as s}from"./chunks/framework.DXGyWiRo.js";const d="/images/image-20260407222614295.png",h=JSON.parse('{"title":"舅舅问11年侄女健康？","description":"","frontmatter":{},"headers":[],"relativePath":"daoism/qimen/examples/jiujiu-question.md","filePath":"daoism/qimen/examples/jiujiu-question.md"}'),g={name:"daoism/qimen/examples/jiujiu-question.md"};function a(r,t,i,o,x,f){return l(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="舅舅问11年侄女健康" tabindex="-1">舅舅问11年侄女健康？ <a class="header-anchor" href="#舅舅问11年侄女健康" aria-label="Permalink to &quot;舅舅问11年侄女健康？&quot;">​</a></h1><blockquote><p>案例取自<a href="https://space.bilibili.com/606383130/?spm_id_from=333.788.upinfo.detail.click" target="_blank" rel="noreferrer">罗江普奇门遁甲</a></p></blockquote><h2 id="补充知识" tabindex="-1">补充知识 <a class="header-anchor" href="#补充知识" aria-label="Permalink to &quot;补充知识&quot;">​</a></h2><h3 id="门迫与门破" tabindex="-1">门迫与门破 <a class="header-anchor" href="#门迫与门破" aria-label="Permalink to &quot;门迫与门破&quot;">​</a></h3><ul><li><p><strong>门破</strong>：指门本身的五行被宫位五行所克，即“宫克门”。例如开门属金落离宫（火），火克金，为门破。门破主门的力量受损。</p></li><li><p><strong>门迫</strong>：指门克宫，即门的五行克制宫位的五行。例如伤门属木落坤宫（土），木克土，为门迫。门迫主该宫位能量受压迫、扭曲，主凶。</p><blockquote><p><strong>门迫</strong>是“门欺负宫”——如同恶客欺主，把人家屋子（宫位）砸了，屋主遭殃。</p><p><strong>门破</strong>是“宫欺负门”——如同主人强势，把客人（八门）的手脚捆住，客人本事再大也发挥不出来。</p></blockquote></li><li><p>门迫</p><table tabindex="0"><thead><tr><th style="text-align:left;">八门</th><th style="text-align:left;">门五行</th><th style="text-align:left;">门迫宫位</th><th style="text-align:left;">被克宫位五行</th><th style="text-align:left;">门迫主事（宫位遭破坏的表现）</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>休门</strong></td><td style="text-align:left;">水</td><td style="text-align:left;"><strong>离宫</strong></td><td style="text-align:left;">火</td><td style="text-align:left;">安逸变懒惰，计划搁浅，热情被浇灭，人际失和。</td></tr><tr><td style="text-align:left;"><strong>生门</strong></td><td style="text-align:left;">土</td><td style="text-align:left;"><strong>坎宫</strong></td><td style="text-align:left;">水</td><td style="text-align:left;">财源被堵，生长停滞，投资失败，根基不稳。</td></tr><tr><td style="text-align:left;"><strong>伤门</strong></td><td style="text-align:left;">木</td><td style="text-align:left;"><strong>坤宫、艮宫</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">意外伤害，车辆事故，土地纠纷，腹部脾胃受损。</td></tr><tr><td style="text-align:left;"><strong>杜门</strong></td><td style="text-align:left;">木</td><td style="text-align:left;"><strong>坤宫、艮宫</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">处处堵塞，秘密难守，技术故障，求助无门。</td></tr><tr><td style="text-align:left;"><strong>景门</strong></td><td style="text-align:left;">火</td><td style="text-align:left;"><strong>兑宫、乾宫</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">合同文书出错，官非口舌，血光之灾，名誉扫地。</td></tr><tr><td style="text-align:left;"><strong>死门</strong></td><td style="text-align:left;">土</td><td style="text-align:left;"><strong>坎宫</strong></td><td style="text-align:left;">水</td><td style="text-align:left;">事情陷入死局，毫无转机，顽固疾病，停滞不前。</td></tr><tr><td style="text-align:left;"><strong>惊门</strong></td><td style="text-align:left;">金</td><td style="text-align:left;"><strong>震宫、巽宫</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">官司缠身，心惊胆战，流言蜚语，关系破裂。</td></tr><tr><td style="text-align:left;"><strong>开门</strong></td><td style="text-align:left;">金</td><td style="text-align:left;"><strong>震宫、巽宫</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">事业崩盘，开局即败，工作丢失，机遇被毁。</td></tr></tbody></table></li><li><p>门破</p><table tabindex="0"><thead><tr><th style="text-align:left;">八门</th><th style="text-align:left;">门五行</th><th style="text-align:left;">门破宫位</th><th style="text-align:left;">克制宫的五行</th><th style="text-align:left;">门破主事（八门自身失灵的表现）</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>休门</strong></td><td style="text-align:left;">水</td><td style="text-align:left;"><strong>坤宫、艮宫</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">智慧被埋没，想休息却不得安宁，贵人爱莫能助。</td></tr><tr><td style="text-align:left;"><strong>生门</strong></td><td style="text-align:left;">土</td><td style="text-align:left;"><strong>震宫、巽宫</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">财产生意被压制，想赚钱却没路子，产业凋零。</td></tr><tr><td style="text-align:left;"><strong>伤门</strong></td><td style="text-align:left;">木</td><td style="text-align:left;"><strong>兑宫、乾宫</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">竞争不过对手，捕猎反被伤，想调动人力却无人响应。</td></tr><tr><td style="text-align:left;"><strong>杜门</strong></td><td style="text-align:left;">木</td><td style="text-align:left;"><strong>兑宫、乾宫</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">隐藏的技术被破解，想保密却泄密，躲藏却暴露行踪。</td></tr><tr><td style="text-align:left;"><strong>景门</strong></td><td style="text-align:left;">火</td><td style="text-align:left;"><strong>坎宫</strong></td><td style="text-align:left;">水</td><td style="text-align:left;">消息虚假，文书不被认可，前景规划被现实浇灭。</td></tr><tr><td style="text-align:left;"><strong>死门</strong></td><td style="text-align:left;">土</td><td style="text-align:left;"><strong>震宫、巽宫</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">想结束的事情结束不了，死地逢生，拖延不决。</td></tr><tr><td style="text-align:left;"><strong>惊门</strong></td><td style="text-align:left;">金</td><td style="text-align:left;"><strong>离宫</strong></td><td style="text-align:left;">火</td><td style="text-align:left;">律师失言，官司证据被烧毁，惊恐自愈，想吵却吵不起来。</td></tr><tr><td style="text-align:left;"><strong>开门</strong></td><td style="text-align:left;">金</td><td style="text-align:left;"><strong>离宫</strong></td><td style="text-align:left;">火</td><td style="text-align:left;">工作受排挤，事业遭熔断，想出人头地却被规则限制。</td></tr></tbody></table></li></ul><h3 id="化解" tabindex="-1">化解 <a class="header-anchor" href="#化解" aria-label="Permalink to &quot;化解&quot;">​</a></h3><ul><li><p>门迫化解</p><p><strong>核心原则</strong>：门迫是“门克宫”，门太强欺负宫位。化解需要<strong>削弱或泄掉门的过盛五行</strong>，让宫位得以喘息。</p><p><strong>通用方法</strong>：在对应宫位的方位，放置或佩戴能<strong>泄门五行</strong>的物品。</p><h4 id="八门门迫化解对照表" tabindex="-1">八门门迫化解对照表 <a class="header-anchor" href="#八门门迫化解对照表" aria-label="Permalink to &quot;八门门迫化解对照表&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">八门</th><th style="text-align:left;">门五行</th><th style="text-align:left;">门迫宫位</th><th style="text-align:left;">泄门五行的方法</th><th style="text-align:left;">具体化解建议</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>休门</strong></td><td style="text-align:left;">水</td><td style="text-align:left;">离宫</td><td style="text-align:left;"><strong>木</strong> 泄水</td><td style="text-align:left;">在该方位养绿色植物（如富贵竹）、放置木质饰品、穿绿色衣物。</td></tr><tr><td style="text-align:left;"><strong>生门</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">坎宫</td><td style="text-align:left;"><strong>金</strong> 泄土</td><td style="text-align:left;">放置金属摆件（铜器、硬币）、五帝钱、白色或金色物品。</td></tr><tr><td style="text-align:left;"><strong>伤门</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">坤/艮宫</td><td style="text-align:left;"><strong>火</strong> 泄木</td><td style="text-align:left;">放置红色饰品、中国结、开启长明灯、增加红色元素。</td></tr><tr><td style="text-align:left;"><strong>杜门</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">坤/艮宫</td><td style="text-align:left;"><strong>火</strong> 泄木</td><td style="text-align:left;">同上，使用红色、紫色物品，或在该方位点香、蜡烛。</td></tr><tr><td style="text-align:left;"><strong>景门</strong></td><td style="text-align:left;">火</td><td style="text-align:left;">兑/乾宫</td><td style="text-align:left;"><strong>土</strong> 泄火</td><td style="text-align:left;">放置陶瓷、黄水晶、泰山石、方形黄色物品。</td></tr><tr><td style="text-align:left;"><strong>死门</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">坎宫</td><td style="text-align:left;"><strong>金</strong> 泄土</td><td style="text-align:left;">同生门，放置金属物件、铜铃、铜钱、白色物品。</td></tr><tr><td style="text-align:left;"><strong>惊门</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">震/巽宫</td><td style="text-align:left;"><strong>水</strong> 泄金</td><td style="text-align:left;">放置鱼缸、黑色物品、水景摆件、蓝黑色饰品。</td></tr><tr><td style="text-align:left;"><strong>开门</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">震/巽宫</td><td style="text-align:left;"><strong>水</strong> 泄金</td><td style="text-align:left;">同上，使用水元素、黑色或深蓝色物品。</td></tr></tbody></table><blockquote><p><strong>地支辅助</strong>：门迫也可用特定地支时间或物品来化解，如：</p><ul><li>休门迫离宫：用 <strong>丑</strong>（丑为湿土，可晦火蓄水）</li><li>生门迫坎宫：用 <strong>亥</strong>（亥为水，可通关土克水）</li><li>伤门/杜门迫坤艮：用 <strong>戌</strong>（戌为燥土，可泄火存木）</li><li>景门迫兑乾：用 <strong>未</strong>（未为燥土，可泄火生金）</li><li>死门迫坎宫：用 <strong>巳</strong>（巳火生土，土生金，金生水，连环通关）</li><li>惊门/开门迫震巽：用 <strong>辰</strong>（辰为水库，可泄金生木）</li></ul></blockquote></li><li><p>门破</p><p><strong>核心原则</strong>：门破是“宫克门”，宫位太强压制了门。化解需要<strong>增强门自身的五行能量</strong>，同时适当<strong>削弱宫位的克制之力</strong>。</p><p><strong>通用方法</strong>：在对应宫位的方位，放置或佩戴能<strong>扶助门五行</strong>的物品，或使用<strong>通关五行</strong>（即宫生通关、通关生门）。</p><h4 id="八门门破化解对照表" tabindex="-1">八门门破化解对照表 <a class="header-anchor" href="#八门门破化解对照表" aria-label="Permalink to &quot;八门门破化解对照表&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">八门</th><th style="text-align:left;">门五行</th><th style="text-align:left;">门破宫位</th><th style="text-align:left;">扶门 / 通关方法</th><th style="text-align:left;">具体化解建议</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>休门</strong></td><td style="text-align:left;">水</td><td style="text-align:left;">坤/艮宫</td><td style="text-align:left;"><strong>金</strong> 通关（土生金，金生水）</td><td style="text-align:left;">放置金属物件（铜铃、钥匙）、白色物品，用金泄土生水。</td></tr><tr><td style="text-align:left;"><strong>生门</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">震/巽宫</td><td style="text-align:left;"><strong>火</strong> 通关（木生火，火生土）</td><td style="text-align:left;">增加红色元素、点灯、放置电器、红色饰品，用火泄木生土。</td></tr><tr><td style="text-align:left;"><strong>伤门</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">兑/乾宫</td><td style="text-align:left;"><strong>水</strong> 通关（金生水，水生木）</td><td style="text-align:left;">放置黑色/蓝色物品、小鱼缸、水杯，用水泄金生木。</td></tr><tr><td style="text-align:left;"><strong>杜门</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">兑/乾宫</td><td style="text-align:left;"><strong>水</strong> 通关（金生水，水生木）</td><td style="text-align:left;">同上，使用水元素来通关。</td></tr><tr><td style="text-align:left;"><strong>景门</strong></td><td style="text-align:left;">火</td><td style="text-align:left;">坎宫</td><td style="text-align:left;"><strong>木</strong> 通关（水生木，木生火）</td><td style="text-align:left;">养绿植、放置木质摆件、穿绿色，用木泄水生火。</td></tr><tr><td style="text-align:left;"><strong>死门</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">震/巽宫</td><td style="text-align:left;"><strong>火</strong> 通关（木生火，火生土）</td><td style="text-align:left;">同生门，用火元素通关。</td></tr><tr><td style="text-align:left;"><strong>惊门</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">离宫</td><td style="text-align:left;"><strong>土</strong> 通关（火生土，土生金）</td><td style="text-align:left;">放置陶瓷、黄水晶、黄色方形物品，用土泄火生金。</td></tr><tr><td style="text-align:left;"><strong>开门</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">离宫</td><td style="text-align:left;"><strong>土</strong> 通关（火生土，土生金）</td><td style="text-align:left;">同上，使用土元素来通关。</td></tr></tbody></table><blockquote><p><strong>地支辅助</strong>（门破常用通关地支）：</p><ul><li>休门破坤艮：用 <strong>申、酉</strong>（金）</li><li>生门/死门破震巽：用 <strong>巳、午</strong>（火）</li><li>伤门/杜门破兑乾：用 <strong>子、亥</strong>（水）</li><li>景门破坎宫：用 <strong>寅、卯</strong>（木）</li><li>惊门/开门破离宫：用 <strong>辰、戌、丑、未</strong>（土）</li></ul></blockquote></li></ul><h2 id="起盘信息" tabindex="-1">起盘信息 <a class="header-anchor" href="#起盘信息" aria-label="Permalink to &quot;起盘信息&quot;">​</a></h2><ul><li><p>时间：2025年12月6日巳时</p></li><li><p>乙巳年 丁亥月 己酉日 己巳时</p></li><li><table tabindex="0"><thead><tr><th style="text-align:center;">值符 天芮 辛戌 景门 己</th><th style="text-align:center;">九天 天柱 丙 死门 癸</th><th style="text-align:center;">九地 天心 乙 惊门 辛戌</th></tr></thead><tbody><tr><td style="text-align:center;">腾蛇 天英 癸 杜门 庚</td><td style="text-align:center;"></td><td style="text-align:center;">玄武 天蓬 壬 开门 丙</td></tr><tr><td style="text-align:center;">太阴 天辅 己 伤门 丁</td><td style="text-align:center;">六合 天冲 庚 生门 壬</td><td style="text-align:center;">白虎 空马 天任 丁 休门 乙</td></tr></tbody></table></li></ul><p><img src="'+d+'" alt="image-20260407222614295"></p><h2 id="解盘思路" tabindex="-1">解盘思路 <a class="header-anchor" href="#解盘思路" aria-label="Permalink to &quot;解盘思路&quot;">​</a></h2><h3 id="用神" tabindex="-1">用神： <a class="header-anchor" href="#用神" aria-label="Permalink to &quot;用神：&quot;">​</a></h3><p>天芮星：主疾病</p><p>时干：长辈测晚辈</p><p>辛卯：2011年</p><h3 id="解盘" tabindex="-1">解盘： <a class="header-anchor" href="#解盘" aria-label="Permalink to &quot;解盘：&quot;">​</a></h3><ol><li>天芮星临值符，值符代表头，临景门（思想），所以是思想或者精神方面的问题，那么看是抑郁症还是精神病</li><li>时干：己+丁临伤门，伤门门迫，伤门临艮宫门迫，（断情感的时候，用神临伤门，特别是门迫的时候，指代有暴力倾向），所以这里从卦象显示这个孩子有暴力倾向（伤害人或者伤害自己），这里己指代自己，己临伤门（自己可能不想活了）。而且己丁都处在一个入墓的位置，己是坑，丁是刀。所以这里精神病占比多一些。</li><li>己下临丁，丁又刚好是月柱的月干，所以很严重</li></ol><h3 id="解决" tabindex="-1">解决： <a class="header-anchor" href="#解决" aria-label="Permalink to &quot;解决：&quot;">​</a></h3><ol><li>往西北方找医生治疗（案例中西北是首都），医生临白虎，白虎这里指代手术过硬的，且这里是乾宫，所以找权威机构。（科学手段）</li><li>运筹不会</li></ol>',19)])])}const p=e(g,[["render",a]]);export{h as __pageData,p as default};
